import{_ as r,o as l,c as o,a7 as t}from"./chunks/framework.C5fSpjcB.js";const u=JSON.parse('{"title":"构筑指南","description":"","frontmatter":{},"headers":[],"relativePath":"cards/deckbuilding.md","filePath":"zh/cards/deckbuilding.md","lastUpdated":1775394001000}'),i={name:"cards/deckbuilding.md"};function e(n,a,s,h,d,g){return l(),o("div",null,[...a[0]||(a[0]=[t('<h1 id="构筑指南" tabindex="-1">构筑指南 <a class="header-anchor" href="#构筑指南" aria-label="Permalink to &quot;构筑指南&quot;">​</a></h1><h2 id="构筑基础" tabindex="-1">构筑基础 <a class="header-anchor" href="#构筑基础" aria-label="Permalink to &quot;构筑基础&quot;">​</a></h2><p>忘却前夜的卡组构筑取决于选择的唤醒体阵容。每位唤醒体贡献自己的 4 张指令卡 + 1 张灵魂觉醒卡。</p><h3 id="构筑原则" tabindex="-1">构筑原则 <a class="header-anchor" href="#构筑原则" aria-label="Permalink to &quot;构筑原则&quot;">​</a></h3><ol><li><strong>界域统一</strong> - 同界域唤醒体的卡牌协同效果更好</li><li><strong>算力曲线</strong> - 注意卡牌的算力消耗分布，避免全部高费</li><li><strong>核心 combo</strong> - 找到核心的卡牌连携组合</li><li><strong>防御/回复</strong> - 不要忽视防御和回复能力</li></ol><h2 id="按界域的构筑思路" tabindex="-1">按界域的构筑思路 <a class="header-anchor" href="#按界域的构筑思路" aria-label="Permalink to &quot;按界域的构筑思路&quot;">​</a></h2><h3 id="深海-aequor-构筑" tabindex="-1">深海（Aequor）构筑 <a class="header-anchor" href="#深海-aequor-构筑" aria-label="Permalink to &quot;深海（Aequor）构筑&quot;">​</a></h3><ul><li><strong>核心思路</strong>: 召唤大量触手，持续造成范围伤害</li><li><strong>关键卡牌</strong>: 详见各角色页面</li><li><strong>优点</strong>: 场控强，持续输出稳定</li><li><strong>缺点</strong>: 爆发相对较低</li></ul><h3 id="血肉-caro-构筑" tabindex="-1">血肉（Caro）构筑 <a class="header-anchor" href="#血肉-caro-构筑" aria-label="Permalink to &quot;血肉（Caro）构筑&quot;">​</a></h3><ul><li><strong>核心思路</strong>: 生成胚胎卡，通过吞噬/消耗触发强力效果</li><li><strong>关键卡牌</strong>: 详见各角色页面</li><li><strong>优点</strong>: 爆发极高</li><li><strong>缺点</strong>: 需要回合积累，启动较慢</li></ul><h3 id="超维-ultra-构筑" tabindex="-1">超维（Ultra）构筑 <a class="header-anchor" href="#超维-ultra-构筑" aria-label="Permalink to &quot;超维（Ultra）构筑&quot;">​</a></h3><ul><li><strong>核心思路</strong>: 利用额外回合机制实现高速连击</li><li><strong>关键卡牌</strong>: 详见各角色页面</li><li><strong>优点</strong>: 行动频率高，节奏快</li><li><strong>缺点</strong>: 对算力管理要求高</li></ul><h3 id="混沌-chaos-混搭" tabindex="-1">混沌（Chaos）混搭 <a class="header-anchor" href="#混沌-chaos-混搭" aria-label="Permalink to &quot;混沌（Chaos）混搭&quot;">​</a></h3><ul><li><strong>核心思路</strong>: 混搭不同界域优势，加速银钥能量</li><li><strong>关键卡牌</strong>: 详见各角色页面</li><li><strong>优点</strong>: 灵活性高</li><li><strong>缺点</strong>: 界域专属协同较弱</li></ul><h2 id="进阶技巧" tabindex="-1">进阶技巧 <a class="header-anchor" href="#进阶技巧" aria-label="Permalink to &quot;进阶技巧&quot;">​</a></h2><ul><li>注意狂气的积累和爆发时机</li><li>合理利用银钥/钥令系统作为额外输出</li><li>在调查行动中注意获取适合当前构筑的临时卡牌</li></ul>',16)])])}const b=r(i,[["render",e]]);export{u as __pageData,b as default};
